# List all registered identity providers with type and claim mapping
$idps = Get-MgIdentityProvider
foreach ($idp in $idps) {
    Write-Host "--- $($idp.DisplayName) ($($idp.AdditionalProperties['@odata.type'])) ---"
    if ($idp.AdditionalProperties.claimsMapping) {
        $idp.AdditionalProperties.claimsMapping | ConvertTo-Json -Depth 3
    } else {
        Write-Host '  (no custom claims mapping)'
    }
}

# Create a claims mapping policy that includes extension attributes
$policyBody = @{
    definition = @(
        ConvertTo-Json @{
            ClaimsMappingPolicy = @{
                Version = 1
                IncludeBasicClaimSet = 'true'
                ClaimsSchema = @(
                    @{ Source='user'; ID='extensionAttribute1'; JwtClaimType='preferred_tier' }
                    @{ Source='user'; ID='city'; JwtClaimType='location' }
                )
            }
        } -Compress
    )
    displayName = 'ExternalIDCustomClaims'
    isOrganizationDefault = $false
}

New-MgPolicyClaimMappingPolicy -BodyParameter $policyBody

Connect-MgGraph -Scopes 'IdentityProvider.ReadWrite.All'

# Find the IdP to remove
$targetName = 'Facebook'
$idp = Get-MgIdentityProvider | Where-Object { $_.DisplayName -eq $targetName }

if (-not $idp) {
    Write-Warning "IdP '$targetName' not found."
    return
}

# Step 1: Remove from all user flows first
$flows = Get-MgIdentityAuthenticationEventFlow
foreach ($flow in $flows) {
    $linked = Get-MgIdentityAuthenticationEventFlowAsExternalUsersSelfServiceSignUpIdentityProvider `
        -AuthenticationEventsFlowId $flow.Id -ErrorAction SilentlyContinue
    if ($linked | Where-Object { $_.Id -eq $idp.Id }) {
        Remove-MgIdentityAuthenticationEventFlowAsExternalUsersSelfServiceSignUpIdentityProviderByRef `
            -AuthenticationEventsFlowId $flow.Id `
            -IdentityProviderId $idp.Id
        Write-Host "Removed from flow: $($flow.DisplayName)"
    }
}

# Step 2: Delete the IdP object
Remove-MgIdentityProvider -IdentityProviderBaseId $idp.Id
Write-Host "Deleted IdP: $targetName"

terraform {
  required_providers {
    azuread = {
      source  = "hashicorp/azuread"
      version = "~> 2.50"
    }
  }
}

# Google Social IdP
resource "azuread_identity_provider" "google" {
  display_name           = "Google"
  identity_provider_type = "Google"
  client_id              = var.google_client_id
  client_secret          = var.google_client_secret
}

# Custom OIDC IdP (e.g. Okta)
resource "azuread_identity_provider" "okta" {
  display_name           = "Okta"
  identity_provider_type = "OpenIdConnect"
  client_id              = var.okta_client_id
  client_secret          = var.okta_client_secret
  metadata_url           = "https://contoso.okta.com/.well-known/openid-configuration"
  domain_hint            = "contoso.com"
  response_type          = "code"
  scope                  = "openid profile email"

  claims_mapping {
    user_id      = "sub"
    display_name = "name"
    email        = "email"
    given_name   = "given_name"
    surname      = "family_name"
  }
}

variable "google_client_id"     { sensitive = true }
variable "google_client_secret"  { sensitive = true }
variable "okta_client_id"        { sensitive = true }
variable "okta_client_secret"    { sensitive = true }
